  1→//! Operation state management and caches.
  2→//!
  3→//! Contains state tracking for in-progress operations and status caches for query APIs.
  4→
  5→use std::collections::HashMap;
  6→use std::path::PathBuf;
  7→use std::sync::atomic::{AtomicBool, Ordering};
  8→use std::sync::{Arc, LazyLock, RwLock};
  9→use std::time::Duration;
 10→
 11→use super::types::{ConflictResolution, OperationStatus, OperationSummary, WriteOperationPhase, WriteOperationType};
 12→
 13→// ============================================================================
 14→// Operation state
 15→// ============================================================================
 16→
 17→/// State for an in-progress write operation.
 18→pub struct WriteOperationState {
 19→    /// Arc so it can be shared with native copy operations.
 20→    pub cancelled: Arc<AtomicBool>,
 21→    /// When true, keep partial files on cancellation.
 22→    pub skip_rollback: AtomicBool,
 23→    pub progress_interval: Duration,
 24→    /// Set by `resolve_write_conflict`.
 25→    pub pending_resolution: RwLock<Option<ConflictResolutionResponse>>,
 26→    pub conflict_condvar: std::sync::Condvar,
 27→    pub conflict_mutex: std::sync::Mutex<bool>,
 28→}
 29→
 30→/// Response to a conflict resolution request.
 31→#[derive(Debug, Clone)]
 32→pub struct ConflictResolutionResponse {
 33→    pub resolution: ConflictResolution,
 34→    pub apply_to_all: bool,
 35→}
 36→
 37→/// Global cache for in-progress write operation states.
 38→pub(super) static WRITE_OPERATION_STATE: LazyLock<RwLock<HashMap<String, Arc<WriteOperationState>>>> =
 39→    LazyLock::new(|| RwLock::new(HashMap::new()));
 40→
 41→/// Global cache for operation status (for query APIs).
 42→static OPERATION_STATUS_CACHE: LazyLock<RwLock<HashMap<String, OperationStatusInternal>>> =
 43→    LazyLock::new(|| RwLock::new(HashMap::new()));
 44→
 45→/// Internal status tracking for operations.
 46→#[derive(Debug, Clone)]
 47→struct OperationStatusInternal {
 48→    operation_type: WriteOperationType,
 49→    phase: WriteOperationPhase,
 50→    current_file: Option<String>,
 51→    files_done: usize,
 52→    files_total: usize,
 53→    bytes_done: u64,
 54→    bytes_total: u64,
 55→    started_at: u64,
 56→}
 57→
 58→// ============================================================================
 59→// Status cache management
 60→// ============================================================================
 61→
 62→/// Updates the internal status for an operation.
 63→pub(super) fn update_operation_status(
 64→    operation_id: &str,
 65→    phase: WriteOperationPhase,
 66→    current_file: Option<String>,
 67→    files_done: usize,
 68→    files_total: usize,
 69→    bytes_done: u64,
 70→    bytes_total: u64,
 71→) {
 72→    if let Ok(mut cache) = OPERATION_STATUS_CACHE.write()
 73→        && let Some(status) = cache.get_mut(operation_id)
 74→    {
 75→        status.phase = phase;
 76→        status.current_file = current_file;
 77→        status.files_done = files_done;
 78→        status.files_total = files_total;
 79→        status.bytes_done = bytes_done;
 80→        status.bytes_total = bytes_total;
 81→    }
 82→}
 83→
 84→/// Registers a new operation in the status cache.
 85→pub(super) fn register_operation_status(operation_id: &str, operation_type: WriteOperationType) {
 86→    let now = std::time::SystemTime::now()
 87→        .duration_since(std::time::UNIX_EPOCH)
 88→        .map(|d| d.as_millis() as u64)
 89→        .unwrap_or(0);
 90→
 91→    if let Ok(mut cache) = OPERATION_STATUS_CACHE.write() {
 92→        cache.insert(
 93→            operation_id.to_string(),
 94→            OperationStatusInternal {
 95→                operation_type,
 96→                phase: WriteOperationPhase::Scanning,
 97→                current_file: None,
 98→                files_done: 0,
 99→                files_total: 0,
100→                bytes_done: 0,
101→                bytes_total: 0,
102→                started_at: now,
103→            },
104→        );
105→    }
106→}
107→
108→/// Removes an operation from the status cache.
109→pub(super) fn unregister_operation_status(operation_id: &str) {
110→    if let Ok(mut cache) = OPERATION_STATUS_CACHE.write() {
111→        cache.remove(operation_id);
112→    }
113→}
114→
115→// ============================================================================
116→// Public query functions
117→// ============================================================================
118→
119→/// Lists all active write operations.
120→///
121→/// Returns a list of operation summaries for all currently running operations.
122→/// This is useful for showing a global progress view or managing multiple concurrent operations.
123→pub fn list_active_operations() -> Vec<OperationSummary> {
124→    let cache = match OPERATION_STATUS_CACHE.read() {
125→        Ok(c) => c,
126→        Err(_) => return Vec::new(),
127→    };
128→
129→    cache
130→        .iter()
131→        .map(|(id, status)| {
132→            let percent_complete = if status.bytes_total > 0 {
133→                ((status.bytes_done as f64 / status.bytes_total as f64) * 100.0).min(100.0) as u8
134→            } else if status.files_total > 0 {
135→                ((status.files_done as f64 / status.files_total as f64) * 100.0).min(100.0) as u8
136→            } else {
137→                0
138→            };
139→
140→            OperationSummary {
141→                operation_id: id.clone(),
142→                operation_type: status.operation_type,
143→                phase: status.phase,
144→                percent_complete,
145→                started_at: status.started_at,
146→            }
147→        })
148→        .collect()
149→}
150→
151→/// Gets the detailed status of a specific operation.
152→///
153→/// Returns `None` if the operation is not found (either never existed or already completed).
154→pub fn get_operation_status(operation_id: &str) -> Option<OperationStatus> {
155→    let cache = OPERATION_STATUS_CACHE.read().ok()?;
156→    let status = cache.get(operation_id)?;
157→
158→    // Check if the operation is still running
159→    let is_running = WRITE_OPERATION_STATE
160→        .read()
161→        .ok()
162→        .map(|c| c.contains_key(operation_id))
163→        .unwrap_or(false);
164→
165→    Some(OperationStatus {
166→        operation_id: operation_id.to_string(),
167→        operation_type: status.operation_type,
168→        phase: status.phase,
169→        is_running,
170→        current_file: status.current_file.clone(),
171→        files_done: status.files_done,
172→        files_total: status.files_total,
173→        bytes_done: status.bytes_done,
174→        bytes_total: status.bytes_total,
175→        started_at: status.started_at,
176→    })
177→}
178→
179→/// Cancels an in-progress write operation.
180→///
181→/// # Arguments
182→/// * `operation_id` - The operation ID to cancel
183→/// * `rollback` - If true, delete any partial files created. If false, keep them.
184→pub fn cancel_write_operation(operation_id: &str, rollback: bool) {
185→    if let Ok(cache) = WRITE_OPERATION_STATE.read()
186→        && let Some(state) = cache.get(operation_id)
187→    {
188→        state.cancelled.store(true, Ordering::Relaxed);
189→        state.skip_rollback.store(!rollback, Ordering::Relaxed);
190→        // Wake up any waiting conflict resolution
191→        let _guard = state.conflict_mutex.lock();
192→        state.conflict_condvar.notify_all();
193→    }
194→}
195→
196→/// Cancels all in-progress write operations with rollback.
197→///
198→/// Used as a safety net when the frontend is tearing down (beforeunload, hot-reload).
199→pub fn cancel_all_write_operations() {
200→    if let Ok(cache) = WRITE_OPERATION_STATE.read() {
201→        for (id, state) in cache.iter() {
202→            if !state.cancelled.load(Ordering::Relaxed) {
203→                log::info!("cancel_all_write_operations: cancelling op={id}");
204→                state.cancelled.store(true, Ordering::Relaxed);
205→                state.skip_rollback.store(false, Ordering::Relaxed);
206→                let _guard = state.conflict_mutex.lock();
207→                state.conflict_condvar.notify_all();
208→            }
209→        }
210→    }
211→}
212→
213→/// Resolves a pending conflict for an in-progress write operation.
214→///
215→/// When an operation encounters a conflict in Stop mode, it emits a WriteConflictEvent
216→/// and waits for this function to be called. The operation will then proceed with the
217→/// chosen resolution.
218→///
219→/// # Arguments
220→/// * `operation_id` - The operation ID that has a pending conflict
221→/// * `resolution` - How to resolve the conflict (Skip, Overwrite, or Rename)
222→/// * `apply_to_all` - If true, apply this resolution to all future conflicts in this operation
223→pub fn resolve_write_conflict(operation_id: &str, resolution: ConflictResolution, apply_to_all: bool) {
224→    if let Ok(cache) = WRITE_OPERATION_STATE.read()
225→        && let Some(state) = cache.get(operation_id)
226→    {
227→        // Set the pending resolution
228→        if let Ok(mut pending) = state.pending_resolution.write() {
229→            *pending = Some(ConflictResolutionResponse {
230→                resolution,
231→                apply_to_all,
232→            });
233→        }
234→        // Wake up the waiting operation
235→        let _guard = state.conflict_mutex.lock();
236→        state.conflict_condvar.notify_all();
237→    }
238→}
239→
240→// ============================================================================
241→// Scan preview state
242→// ============================================================================
243→
244→/// State for a scan preview operation.
245→pub(super) struct ScanPreviewState {
246→    pub cancelled: AtomicBool,
247→    pub progress_interval: Duration,
248→}
249→
250→/// Cached result from a completed scan preview.
251→#[allow(dead_code, reason = "Fields read via take_cached_scan_result")]
252→pub(super) struct CachedScanResult {
253→    pub files: Vec<FileInfo>,
254→    pub dirs: Vec<PathBuf>,
255→    pub file_count: usize,
256→    pub total_bytes: u64,
257→}
258→
259→/// Global cache for scan preview states.
260→pub(super) static SCAN_PREVIEW_STATE: LazyLock<RwLock<HashMap<String, Arc<ScanPreviewState>>>> =
261→    LazyLock::new(|| RwLock::new(HashMap::new()));
262→
263→/// Global cache for completed scan preview results.
264→pub(super) static SCAN_PREVIEW_RESULTS: LazyLock<RwLock<HashMap<String, CachedScanResult>>> =
265→    LazyLock::new(|| RwLock::new(HashMap::new()));
266→
267→// ============================================================================
268→// FileInfo (used for scanning and sorting)
269→// ============================================================================
270→
271→/// File info collected during scan (used for sorting).
272→#[derive(Debug, Clone)]
273→pub(super) struct FileInfo {
274→    pub path: PathBuf,
275→    /// Parent of the original source (used to compute relative path for destination)
276→    pub source_root: PathBuf,
277→    pub size: u64,
278→    pub modified: u64, // Unix timestamp in seconds
279→    pub created: u64,  // Unix timestamp in seconds
280→    pub is_symlink: bool,
281→}
282→
283→impl FileInfo {
284→    pub fn new(path: PathBuf, source_root: PathBuf, metadata: &std::fs::Metadata) -> Self {
285→        use std::time::UNIX_EPOCH;
286→        Self {
287→            path,
288→            source_root,
289→            size: metadata.len(),
290→            modified: metadata
291→                .modified()
292→                .ok()
293→                .and_then(|t| t.duration_since(UNIX_EPOCH).ok())
294→                .map(|d| d.as_secs())
295→                .unwrap_or(0),
296→            created: metadata
297→                .created()
298→                .ok()
299→                .and_then(|t| t.duration_since(UNIX_EPOCH).ok())
300→                .map(|d| d.as_secs())
301→                .unwrap_or(0),
302→            is_symlink: metadata.is_symlink(),
303→        }
304→    }
305→
306→    /// Get extension for sorting (lowercase, empty string if none).
307→    pub fn extension(&self) -> String {
308→        self.path
309→            .extension()
310→            .map(|e| e.to_string_lossy().to_lowercase())
311→            .unwrap_or_default()
312→    }
313→
314→    /// Get filename for sorting (lowercase).
315→    pub fn name_lower(&self) -> String {
316→        self.path
317→            .file_name()
318→            .map(|n| n.to_string_lossy().to_lowercase())
319→            .unwrap_or_default()
320→    }
321→
322→    /// Compute the destination path for this file given the destination root.
323→    pub fn dest_path(&self, destination: &std::path::Path) -> PathBuf {
324→        // Strip source_root from path to get relative path, then join with destination
325→        if let Ok(relative) = self.path.strip_prefix(&self.source_root) {
326→            destination.join(relative)
327→        } else {
328→            // Fallback: just use the filename
329→            destination.join(self.path.file_name().unwrap_or_default())
330→        }
331→    }
332→}
333→
334→/// Information about files to be processed.
335→pub(super) struct ScanResult {
336→    pub files: Vec<FileInfo>,
337→    /// For deletion: in reverse order, deepest first.
338→    pub dirs: Vec<PathBuf>,
339→    /// Not including directories.
340→    pub file_count: usize,
341→    pub total_bytes: u64,
342→}
343→
344→// ============================================================================
345→// Copy transaction for rollback
346→// ============================================================================
347→
348→/// Tracks created files/directories for rollback on failure.
349→///
350→/// If dropped without calling `commit()`, automatically rolls back
351→/// (deletes) all recorded files and directories. This ensures cleanup
352→/// even if a thread panics during the copy loop.
353→#[cfg_attr(test, derive(Debug))]
354→pub(crate) struct CopyTransaction {
355→    /// In creation order.
356→    pub created_files: Vec<PathBuf>,
357→    /// In creation order.
358→    pub created_dirs: Vec<PathBuf>,
359→    /// Set to `true` by `commit()` to prevent rollback on drop.
360→    committed: bool,
361→}
362→
363→impl CopyTransaction {
364→    pub fn new() -> Self {
365→        Self {
366→            created_files: Vec::new(),
367→            created_dirs: Vec::new(),
368→            committed: false,
369→        }
370→    }
371→
372→    pub fn record_file(&mut self, path: PathBuf) {
373→        self.created_files.push(path);
374→    }
375→
376→    pub fn record_dir(&mut self, path: PathBuf) {
377→        self.created_dirs.push(path);
378→    }
379→
380→    /// Rolls back all created files and directories.
381→    pub fn rollback(&self) {
382→        // Delete files first (in reverse order)
383→        for file in self.created_files.iter().rev() {
384→            let _ = std::fs::remove_file(file);
385→        }
386→        // Then directories (deepest first, already in reverse due to creation order)
387→        for dir in self.created_dirs.iter().rev() {
388→            let _ = std::fs::remove_dir(dir);
389→        }
390→    }
391→
392→    /// Marks the transaction as committed, preventing rollback on drop.
393→    pub fn commit(mut self) {
394→        self.committed = true;
395→    }
396→}
397→
398→impl Drop for CopyTransaction {
399→    fn drop(&mut self) {
400→        if !self.committed {
401→            log::warn!(
402→                "CopyTransaction dropped without commit, rolling back {} files and {} dirs",
403→                self.created_files.len(),
404→                self.created_dirs.len()
405→            );
406→            self.rollback();
407→        }
408→    }
409→}
