//! Operation state management and caches.
//!
//! Contains state tracking for in-progress operations and status caches for query APIs.

use std::collections::HashMap;
use std::path::PathBuf;
use std::sync::atomic::{AtomicBool, Ordering};
use std::sync::{Arc, LazyLock, RwLock};
use std::time::Duration;

use super::types::{ConflictResolution, OperationStatus, OperationSummary, WriteOperationPhase, WriteOperationType};

// ============================================================================
// Operation state
// ============================================================================

/// State for an in-progress write operation.
pub struct WriteOperationState {
    /// Arc so it can be shared with native copy operations.
    pub cancelled: Arc<AtomicBool>,
    /// When true, keep partial files on cancellation.
    pub skip_rollback: AtomicBool,
    pub progress_interval: Duration,
    /// Set by `resolve_write_conflict`.
    pub pending_resolution: RwLock<Option<ConflictResolutionResponse>>,
    pub conflict_condvar: std::sync::Condvar,
    pub conflict_mutex: std::sync::Mutex<bool>,
}

/// Response to a conflict resolution request.
#[derive(Debug, Clone)]
pub struct ConflictResolutionResponse {
    pub resolution: ConflictResolution,
    pub apply_to_all: bool,
}

/// Global cache for in-progress write operation states.
pub(super) static WRITE_OPERATION_STATE: LazyLock<RwLock<HashMap<String, Arc<WriteOperationState>>>> =
    LazyLock::new(|| RwLock::new(HashMap::new()));

/// Global cache for operation status (for query APIs).
static OPERATION_STATUS_CACHE: LazyLock<RwLock<HashMap<String, OperationStatusInternal>>> =
    LazyLock::new(|| RwLock::new(HashMap::new()));

/// Internal status tracking for operations.
#[derive(Debug, Clone)]
struct OperationStatusInternal {
    operation_type: WriteOperationType,
    phase: WriteOperationPhase,
    current_file: Option<String>,
    files_done: usize,
    files_total: usize,
    bytes_done: u64,
    bytes_total: u64,
    started_at: u64,
}

// ============================================================================
// Status cache management
// ============================================================================

/// Updates the internal status for an operation.
pub(super) fn update_operation_status(
    operation_id: &str,
    phase: WriteOperationPhase,
    current_file: Option<String>,
    files_done: usize,
    files_total: usize,
    bytes_done: u64,
    bytes_total: u64,
) {
    if let Ok(mut cache) = OPERATION_STATUS_CACHE.write()
        && let Some(status) = cache.get_mut(operation_id)
    {
        status.phase = phase;
        status.current_file = current_file;
        status.files_done = files_done;
        status.files_total = files_total;
        status.bytes_done = bytes_done;
        status.bytes_total = bytes_total;
    }
}

/// Registers a new operation in the status cache.
pub(super) fn register_operation_status(operation_id: &str, operation_type: WriteOperationType) {
    let now = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .map(|d| d.as_millis() as u64)
        .unwrap_or(0);

    if let Ok(mut cache) = OPERATION_STATUS_CACHE.write() {
        cache.insert(
            operation_id.to_string(),
            OperationStatusInternal {
                operation_type,
                phase: WriteOperationPhase::Scanning,
                current_file: None,
                files_done: 0,
                files_total: 0,
                bytes_done: 0,
                bytes_total: 0,
                started_at: now,
            },
        );
    }
}

/// Removes an operation from the status cache.
pub(super) fn unregister_operation_status(operation_id: &str) {
    if let Ok(mut cache) = OPERATION_STATUS_CACHE.write() {
        cache.remove(operation_id);
    }
}

// ============================================================================
// Public query functions
// ============================================================================

/// Lists all active write operations.
///
/// Returns a list of operation summaries for all currently running operations.
/// This is useful for showing a global progress view or managing multiple concurrent operations.
pub fn list_active_operations() -> Vec<OperationSummary> {
    let cache = match OPERATION_STATUS_CACHE.read() {
        Ok(c) => c,
        Err(_) => return Vec::new(),
    };

    cache
        .iter()
        .map(|(id, status)| {
            let percent_complete = if status.bytes_total > 0 {
                ((status.bytes_done as f64 / status.bytes_total as f64) * 100.0).min(100.0) as u8
            } else if status.files_total > 0 {
                ((status.files_done as f64 / status.files_total as f64) * 100.0).min(100.0) as u8
            } else {
                0
            };

            OperationSummary {
                operation_id: id.clone(),
                operation_type: status.operation_type,
                phase: status.phase,
                percent_complete,
                started_at: status.started_at,
            }
        })
        .collect()
}

/// Gets the detailed status of a specific operation.
///
/// Returns `None` if the operation is not found (either never existed or already completed).
pub fn get_operation_status(operation_id: &str) -> Option<OperationStatus> {
    let cache = OPERATION_STATUS_CACHE.read().ok()?;
    let status = cache.get(operation_id)?;

    // Check if the operation is still running
    let is_running = WRITE_OPERATION_STATE
        .read()
        .ok()
        .map(|c| c.contains_key(operation_id))
        .unwrap_or(false);

    Some(OperationStatus {
        operation_id: operation_id.to_string(),
        operation_type: status.operation_type,
        phase: status.phase,
        is_running,
        current_file: status.current_file.clone(),
        files_done: status.files_done,
        files_total: status.files_total,
        bytes_done: status.bytes_done,
        bytes_total: status.bytes_total,
        started_at: status.started_at,
    })
}

/// Cancels an in-progress write operation.
///
/// # Arguments
/// * `operation_id` - The operation ID to cancel
/// * `rollback` - If true, delete any partial files created. If false, keep them.
pub fn cancel_write_operation(operation_id: &str, rollback: bool) {
    if let Ok(cache) = WRITE_OPERATION_STATE.read()
        && let Some(state) = cache.get(operation_id)
    {
        state.cancelled.store(true, Ordering::Relaxed);
        state.skip_rollback.store(!rollback, Ordering::Relaxed);
        // Wake up any waiting conflict resolution
        let _guard = state.conflict_mutex.lock();
        state.conflict_condvar.notify_all();
    }
}

/// Cancels all in-progress write operations with rollback.
///
/// Used as a safety net when the frontend is tearing down (beforeunload, hot-reload).
pub fn cancel_all_write_operations() {
    if let Ok(cache) = WRITE_OPERATION_STATE.read() {
        for (id, state) in cache.iter() {
            if !state.cancelled.load(Ordering::Relaxed) {
                log::info!("cancel_all_write_operations: cancelling op={id}");
                state.cancelled.store(true, Ordering::Relaxed);
                state.skip_rollback.store(false, Ordering::Relaxed);
                let _guard = state.conflict_mutex.lock();
                state.conflict_condvar.notify_all();
            }
        }
    }
}

/// Resolves a pending conflict for an in-progress write operation.
///
/// When an operation encounters a conflict in Stop mode, it emits a WriteConflictEvent
/// and waits for this function to be called. The operation will then proceed with the
/// chosen resolution.
///
/// # Arguments
/// * `operation_id` - The operation ID that has a pending conflict
/// * `resolution` - How to resolve the conflict (Skip, Overwrite, or Rename)
/// * `apply_to_all` - If true, apply this resolution to all future conflicts in this operation
pub fn resolve_write_conflict(operation_id: &str, resolution: ConflictResolution, apply_to_all: bool) {
    if let Ok(cache) = WRITE_OPERATION_STATE.read()
        && let Some(state) = cache.get(operation_id)
    {
        // Set the pending resolution
        if let Ok(mut pending) = state.pending_resolution.write() {
            *pending = Some(ConflictResolutionResponse {
                resolution,
                apply_to_all,
            });
        }
        // Wake up the waiting operation
        let _guard = state.conflict_mutex.lock();
        state.conflict_condvar.notify_all();
    }
}

// ============================================================================
// Scan preview state
// ============================================================================

/// State for a scan preview operation.
pub(super) struct ScanPreviewState {
    pub cancelled: AtomicBool,
    pub progress_interval: Duration,
}

/// Cached result from a completed scan preview.
#[allow(dead_code, reason = "Fields read via take_cached_scan_result")]
pub(super) struct CachedScanResult {
    pub files: Vec<FileInfo>,
    pub dirs: Vec<PathBuf>,
    pub file_count: usize,
    pub total_bytes: u64,
}

/// Global cache for scan preview states.
pub(super) static SCAN_PREVIEW_STATE: LazyLock<RwLock<HashMap<String, Arc<ScanPreviewState>>>> =
    LazyLock::new(|| RwLock::new(HashMap::new()));

/// Global cache for completed scan preview results.
pub(super) static SCAN_PREVIEW_RESULTS: LazyLock<RwLock<HashMap<String, CachedScanResult>>> =
    LazyLock::new(|| RwLock::new(HashMap::new()));

// ============================================================================
// FileInfo (used for scanning and sorting)
// ============================================================================

/// File info collected during scan (used for sorting).
#[derive(Debug, Clone)]
pub(super) struct FileInfo {
    pub path: PathBuf,
    /// Parent of the original source (used to compute relative path for destination)
    pub source_root: PathBuf,
    pub size: u64,
    pub modified: u64, // Unix timestamp in seconds
    pub created: u64,  // Unix timestamp in seconds
    pub is_symlink: bool,
}

impl FileInfo {
    pub fn new(path: PathBuf, source_root: PathBuf, metadata: &std::fs::Metadata) -> Self {
        use std::time::UNIX_EPOCH;
        Self {
            path,
            source_root,
            size: metadata.len(),
            modified: metadata
                .modified()
                .ok()
                .and_then(|t| t.duration_since(UNIX_EPOCH).ok())
                .map(|d| d.as_secs())
                .unwrap_or(0),
            created: metadata
                .created()
                .ok()
                .and_then(|t| t.duration_since(UNIX_EPOCH).ok())
                .map(|d| d.as_secs())
                .unwrap_or(0),
            is_symlink: metadata.is_symlink(),
        }
    }

    /// Get extension for sorting (lowercase, empty string if none).
    pub fn extension(&self) -> String {
        self.path
            .extension()
            .map(|e| e.to_string_lossy().to_lowercase())
            .unwrap_or_default()
    }

    /// Get filename for sorting (lowercase).
    pub fn name_lower(&self) -> String {
        self.path
            .file_name()
            .map(|n| n.to_string_lossy().to_lowercase())
            .unwrap_or_default()
    }

    /// Compute the destination path for this file given the destination root.
    pub fn dest_path(&self, destination: &std::path::Path) -> PathBuf {
        // Strip source_root from path to get relative path, then join with destination
        if let Ok(relative) = self.path.strip_prefix(&self.source_root) {
            destination.join(relative)
        } else {
            // Fallback: just use the filename
            destination.join(self.path.file_name().unwrap_or_default())
        }
    }
}

/// Information about files to be processed.
pub(super) struct ScanResult {
    pub files: Vec<FileInfo>,
    /// For deletion: in reverse order, deepest first.
    pub dirs: Vec<PathBuf>,
    /// Not including directories.
    pub file_count: usize,
    pub total_bytes: u64,
}

// ============================================================================
// Copy transaction for rollback
// ============================================================================

/// Tracks created files/directories for rollback on failure.
///
/// If dropped without calling `commit()`, automatically rolls back
/// (deletes) all recorded files and directories. This ensures cleanup
/// even if a thread panics during the copy loop.
#[cfg_attr(test, derive(Debug))]
pub(crate) struct CopyTransaction {
    /// In creation order.
    pub created_files: Vec<PathBuf>,
    /// In creation order.
    pub created_dirs: Vec<PathBuf>,
    /// Set to `true` by `commit()` to prevent rollback on drop.
    committed: bool,
}

impl CopyTransaction {
    pub fn new() -> Self {
        Self {
            created_files: Vec::new(),
            created_dirs: Vec::new(),
            committed: false,
        }
    }

    pub fn record_file(&mut self, path: PathBuf) {
        self.created_files.push(path);
    }

    pub fn record_dir(&mut self, path: PathBuf) {
        self.created_dirs.push(path);
    }

    /// Rolls back all created files and directories.
    pub fn rollback(&self) {
        // Delete files first (in reverse order)
        for file in self.created_files.iter().rev() {
            let _ = std::fs::remove_file(file);
        }
        // Then directories (deepest first, already in reverse due to creation order)
        for dir in self.created_dirs.iter().rev() {
            let _ = std::fs::remove_dir(dir);
        }
    }

    /// Marks the transaction as committed, preventing rollback on drop.
    pub fn commit(mut self) {
        self.committed = true;
    }
}

impl Drop for CopyTransaction {
    fn drop(&mut self) {
        if !self.committed {
            log::warn!(
                "CopyTransaction dropped without commit, rolling back {} files and {} dirs",
                self.created_files.len(),
                self.created_dirs.len()
            );
            self.rollback();
        }
    }
}

    copy: 'Copy',
    move: 'Move',
    delete: 'Delete',
    trash: 'Trash',
}
const operationGerundMap: Record<TransferOperationType, string> = {
    copy: 'Copying',
    move: 'Moving',
    delete: 'Deleting',
    trash: 'Moving to trash',
}
const operationLabel = $derived(operationLabelMap[operationType])
const operationGerund = $derived(operationGerundMap[operationType])
const isDeleteOrTrash = $derived(operationType === 'delete' || operationType === 'trash')
const isCopy = $derived(operationType === 'copy')

/** Whether this is a move involving an MTP volume (implemented as copy + delete). */
const isMtpMove = $derived(
    operationType === 'move' && (sourceVolumeId.startsWith('mtp-') || (destVolumeId ?? '').startsWith('mtp-')),
)

/** Tracks which phase of an MTP move we're in: 'copy' first, then 'delete'. */
let mtpMovePhase = $state<'copy' | 'delete'>('copy')

/** Minimum display time (ms) to prevent jarring one-frame flash. */
const MIN_DISPLAY_MS = 400

// Operation state
let operationId = $state<string | null>(null)
let phase = $state<WriteOperationPhase>('scanning')
let currentFile = $state<string | null>(null)
let filesDone = $state(0)
let filesTotal = $state(0)
let bytesDone = $state(0)
let bytesTotal = $state(0)
let startTime = $state(0)
let isCancelling = $state(false)
let isRollingBack = $state(false)
let destroyed = false

// Events that arrived before we know our operationId (from the command response).
// Without buffering, a stale event from a previous operation could claim the ID slot first.
type BufferedEvent =
    | { type: 'progress'; event: WriteProgressEvent }
    | { type: 'complete'; event: WriteCompleteEvent }
    | { type: 'error'; event: WriteErrorEvent }
    | { type: 'cancelled'; event: WriteCancelledEvent }
    | { type: 'conflict'; event: WriteConflictEvent }
let pendingEvents: BufferedEvent[] = []

/** Returns true if the event belongs to this operation and should be processed. */
function filterEvent(entry: BufferedEvent): boolean {
    if (operationId === null) {
        pendingEvents.push(entry)
        return false
    }
    return entry.event.operationId === operationId
}

function replayBufferedEvents() {
    const events = pendingEvents
    pendingEvents = []
    for (const entry of events) {
        if (entry.event.operationId !== operationId) continue
        switch (entry.type) {
            case 'progress':
                handleProgress(entry.event)
                break
            case 'complete':
                handleComplete(entry.event)
                break
            case 'error':
                handleError(entry.event)
                break
            case 'cancelled':
                handleCancelled(entry.event)
                break
            case 'conflict':
                handleConflict(entry.event)
                break
        }
    }
}

// Conflict state
let conflictEvent = $state<WriteConflictEvent | null>(null)
let isResolvingConflict = $state(false)

// Calculated stats
const percentComplete = $derived(bytesTotal > 0 ? (bytesDone / bytesTotal) * 100 : 0)

// Speed and ETA calculation
const stats = $derived.by(() => {
    if (startTime === 0 || bytesDone === 0) {
        return { bytesPerSecond: 0, estimatedSecondsRemaining: null }
    }
    const elapsedSeconds = (Date.now() - startTime) / 1000
    const bytesPerSecond = elapsedSeconds > 0 ? bytesDone / elapsedSeconds : 0
    const bytesRemaining = bytesTotal - bytesDone
    const estimatedSecondsRemaining = bytesPerSecond > 0 ? bytesRemaining / bytesPerSecond : null

    return { bytesPerSecond, estimatedSecondsRemaining }
})

// Progress stages for visualization — the active phase label adapts to operation type.
// MTP moves show three stages: Scanning → Copying → Removing source.
const activePhaseId = $derived<WriteOperationPhase>(
    operationType === 'delete' ? 'deleting' : operationType === 'trash' ? 'trashing' : 'copying',
)
const stages = $derived<{ id: WriteOperationPhase | 'mtp-delete'; label: string }[]>(
    isMtpMove
        ? [
              { id: 'scanning', label: 'Scanning' },
              { id: 'copying', label: 'Copying' },
              { id: 'mtp-delete', label: 'Removing source' },
          ]
        : [
              { id: 'scanning', label: 'Scanning' },
              { id: activePhaseId, label: operationGerund },
          ],
)

function getStageStatus(stageId: WriteOperationPhase | 'mtp-delete'): 'done' | 'active' | 'pending' {
    if (isMtpMove) {
        // MTP move has three stages: scanning → copying → mtp-delete.
        // Map the current backend phase + mtpMovePhase to a stage index.
        let currentIndex: number
        if (mtpMovePhase === 'delete') {
            // In delete phase: scanning and copying are done, mtp-delete is active
            currentIndex = 2
        } else if (phase === 'scanning') {
            currentIndex = 0
        } else {
            currentIndex = 1
        }
        const stageIndex = stages.findIndex((s) => s.id === stageId)
        if (stageIndex < currentIndex) return 'done'
        if (stageIndex === currentIndex) return 'active'
        return 'pending'
    }

    const currentIndex = stages.findIndex((s) => s.id === phase)
    const stageIndex = stages.findIndex((s) => s.id === stageId)

    if (stageIndex < currentIndex) return 'done'
    if (stageIndex === currentIndex) return 'active'
    return 'pending'
}

function handleProgress(event: WriteProgressEvent) {
    if (!filterEvent({ type: 'progress', event })) return

    log.debug('Progress event: {phase} {filesDone}/{filesTotal} files, {bytesDone}/{bytesTotal} bytes', {
        phase: event.phase,
        filesDone: event.filesDone,
        filesTotal: event.filesTotal,
        bytesDone: event.bytesDone,
        bytesTotal: event.bytesTotal,
    })

    phase = event.phase
    currentFile = event.currentFile
    filesDone = event.filesDone
    filesTotal = event.filesTotal
    bytesDone = event.bytesDone
    bytesTotal = event.bytesTotal
}

/** Accumulated totals from the copy phase of an MTP move, added to the final result. */
let mtpMoveCopyResult = { filesProcessed: 0, bytesProcessed: 0 }

function handleComplete(event: WriteCompleteEvent) {
    if (!filterEvent({ type: 'complete', event })) return

    log.info('{op} complete: {filesProcessed} files, {bytesProcessed} bytes', {
        op: operationLabel,
        filesProcessed: event.filesProcessed,
        bytesProcessed: event.bytesProcessed,
    })

    // MTP move, copy phase done → start the delete phase to remove source files
    if (isMtpMove && mtpMovePhase === 'copy') {
        log.info('MTP move copy phase done, starting delete phase for {count} source files', {
            count: sourcePaths.length,
        })
        mtpMoveCopyResult = {
            filesProcessed: event.filesProcessed,
            bytesProcessed: event.bytesProcessed,
        }
        cleanup()
        void startMtpMoveDeletePhase()
        return
    }

    cleanup()

    // For MTP move delete phase, combine totals from both phases
    const totalFiles = isMtpMove ? mtpMoveCopyResult.filesProcessed : event.filesProcessed
    const totalBytes = isMtpMove ? mtpMoveCopyResult.bytesProcessed : event.bytesProcessed

    // Enforce minimum display time to prevent jarring one-frame flash
    const elapsed = Date.now() - startTime
    const delay = Math.max(0, MIN_DISPLAY_MS - elapsed)
    if (delay > 0) {
        setTimeout(() => {
            onComplete(totalFiles, totalBytes)
        }, delay)
    } else {
        onComplete(totalFiles, totalBytes)
    }
}

function handleError(event: WriteErrorEvent) {
    if (!filterEvent({ type: 'error', event })) return

    log.error('{op} error: {errorType}', { op: operationLabel, errorType: event.error.type, error: event.error })

    cleanup()

    // MTP move delete phase error: copy succeeded, but source removal hit a problem.
    // The user has files in both places — safer than losing data.
    if (isMtpMove && mtpMovePhase === 'delete') {
        const errorMessage = 'message' in event.error ? event.error.message : event.error.type
        onError({
            type: 'io_error',
            path: 'path' in event.error ? event.error.path : (sourcePaths[0] ?? ''),
            message: `Copied successfully, but couldn't remove some source files: ${errorMessage}`,
        })
        return
    }

    onError(event.error)
}

function handleCancelled(event: WriteCancelledEvent) {
    if (!filterEvent({ type: 'cancelled', event })) return

    log.info('{op} cancelled after {filesProcessed} files, rolledBack={rolledBack}', {
        op: operationLabel,
        filesProcessed: event.filesProcessed,
        rolledBack: event.rolledBack,
    })

    cleanup()
    onCancelled(event.filesProcessed)
}

function handleConflict(event: WriteConflictEvent) {
    if (!filterEvent({ type: 'conflict', event })) return

    log.info('Conflict detected: {sourcePath} -> {destinationPath}', {

            sourcePath: event.sourcePath,
            destinationPath: event.destinationPath,
        })

        conflictEvent = event
    }

    async function handleConflictResolution(resolution: ConflictResolution, applyToAll: boolean) {
        if (!operationId || !conflictEvent) return

        log.info('Resolving conflict with {resolution}, applyToAll={applyToAll}', { resolution, applyToAll })

        isResolvingConflict = true
        try {
            await resolveWriteConflict(operationId, resolution, applyToAll)
            conflictEvent = null
        } catch (err) {
            log.error('Failed to resolve conflict: {error}', { error: err })
        } finally {
            isResolvingConflict = false
        }
    }

    // Store multiple unlisteners
    let unlisteners: UnlistenFn[] = []

    function cleanup() {
        log.debug('Cleaning up {count} event listeners', { count: unlisteners.length })
        for (const unlisten of unlisteners) {
            unlisten()
        }
        unlisteners = []
    }

    /** Dispatches the backend command based on operation type. */
    async function dispatchOperation(): Promise<{ operationId: string }> {
        const progressIntervalMs = getSetting('fileOperations.progressUpdateInterval')
        const maxConflictsToShow = getSetting('fileOperations.maxConflictsToShow')

        if (operationType === 'trash') {
            return trashFiles(sourcePaths, itemSizes, { progressIntervalMs, previewId })
        }
        if (operationType === 'delete') {
            return deleteFiles(sourcePaths, { progressIntervalMs, sortColumn, sortOrder, previewId }, sourceVolumeId)
        }
        if (operationType === 'move') {
            // MTP move: phase 1 is copy, phase 2 (delete) starts after copy completes
            if (isMtpMove) {
                return copyBetweenVolumes(
                    sourceVolumeId,
                    sourcePaths,
                    destVolumeId ?? DEFAULT_VOLUME_ID,
                    destinationPath ?? '',
                    {
                        conflictResolution,
                        progressIntervalMs,
                        maxConflictsToShow,
                    },
                )
            }
            return moveFiles(sourcePaths, destinationPath ?? '', {
                conflictResolution,
                progressIntervalMs,
                maxConflictsToShow,
                sortColumn,
                sortOrder,
                previewId,
            })
        }
        // Copy: use unified copyBetweenVolumes for cross-volume operations (including MTP)
        const isLocalToLocal = sourceVolumeId === DEFAULT_VOLUME_ID && (destVolumeId ?? '') === DEFAULT_VOLUME_ID
        return isLocalToLocal
            ? copyFiles(sourcePaths, destinationPath ?? '', {
                  conflictResolution,
                  progressIntervalMs,
                  maxConflictsToShow,
                  sortColumn,
                  sortOrder,
                  previewId,
              })
            : copyBetweenVolumes(
                  sourceVolumeId,
                  sourcePaths,
                  destVolumeId ?? DEFAULT_VOLUME_ID,
                  destinationPath ?? '',
                  {
                      conflictResolution,
                      progressIntervalMs,
                      maxConflictsToShow,
                  },
              )
    }

    /** Starts the delete phase of an MTP move after the copy phase completes. */
    async function startMtpMoveDeletePhase() {
        mtpMovePhase = 'delete'
        operationId = null
        pendingEvents = []

        // Reset progress counters for the delete phase
        phase = 'scanning'
        currentFile = null
        filesDone = 0
        filesTotal = 0
        bytesDone = 0
        bytesTotal = 0

        log.info('Starting MTP move delete phase: removing {count} source files', {
            count: sourcePaths.length,
        })

        // Subscribe to events before starting the delete operation
        unlisteners.push(await onWriteProgress(handleProgress))
        unlisteners.push(await onWriteComplete(handleComplete))
        unlisteners.push(await onWriteError(handleError))
        unlisteners.push(await onWriteCancelled(handleCancelled))
        unlisteners.push(await onWriteConflict(handleConflict))

        try {
            const progressIntervalMs = getSetting('fileOperations.progressUpdateInterval')
            const result = await deleteFiles(sourcePaths, { progressIntervalMs, sortColumn, sortOrder }, sourceVolumeId)

            operationId = result.operationId
            log.info('MTP move delete phase started with operationId: {operationId}', {
                operationId,
            })

            if (destroyed) {
                log.info('Dialog destroyed before delete operationId arrived — cancelling op={operationId}', {
                    operationId,
                })
                void cancelWriteOperation(operationId, true)
                cleanup()
                return
            }

            replayBufferedEvents()
        } catch (err: unknown) {
            log.error("MTP move delete phase couldn't start: {error}", { error: err })
            cleanup()
            // Copy succeeded but delete didn't start — report success for the copy part.
            // The user keeps files in both places (safe default).
            onError({
                type: 'io_error',
                path: sourcePaths[0] ?? '',
                message: `Copied successfully, but couldn't remove the source files: ${String(err)}`,
            })
        }
    }

    async function startOperation() {
        log.info('Starting {op} operation: {sourceCount} sources', {
            op: operationType,
            sourceCount: sourcePaths.length,
        })

        startTime = Date.now()

        // CRITICAL: Subscribe to events BEFORE starting the operation to avoid race condition
        // Events are emitted immediately when the operation starts - if we subscribe after,
        // we might miss progress/complete events for fast operations (like single large files)
        log.debug('Subscribing to write events BEFORE starting operation')

        unlisteners.push(await onWriteProgress(handleProgress))
        unlisteners.push(await onWriteComplete(handleComplete))
        unlisteners.push(await onWriteError(handleError))
        unlisteners.push(await onWriteCancelled(handleCancelled))
        unlisteners.push(await onWriteConflict(handleConflict))

        log.debug('Event subscriptions ready, starting {op}', { op: operationType })

        try {
            const result = await dispatchOperation()

            operationId = result.operationId
            log.info('{op} operation started with operationId: {operationId}', {
                op: operationLabel,
                operationId,
            })

            // If the dialog was destroyed/cancelled while waiting for the IPC response,
            // cancel the operation immediately and bail out
            if (destroyed) {
                log.info('Dialog destroyed before operationId arrived — cancelling op={operationId}', {
                    operationId,
                })
                void cancelWriteOperation(operationId, true)
                cleanup()
                return
            }

            replayBufferedEvents()
        } catch (err: unknown) {
            log.error('Failed to start {op} operation: {error}', { op: operationType, error: err })
            cleanup()
            // Tauri commands return structured WriteOperationError objects on validation failure
            // (e.g. destination_inside_source). Pass them through to preserve the specific error type.
            if (typeof err === 'object' && err !== null && 'type' in err) {
                onError(err as WriteOperationError)
            } else {
                onError({
                    type: 'io_error',
                    path: sourcePaths[0] ?? '',
                    message: `Failed to start ${operationType}: ${String(err)}`,
                })
            }
        }
    }

    async function handleCancel(rollback: boolean) {
        if (!operationId) {
            log.warn('Cancel requested but no operationId yet — will cancel after IPC resolves')
            destroyed = true
            return
        }
        if (isCancelling || isRollingBack) {
            log.debug('Cancel/rollback already in progress')
            return
        }

        if (rollback) {
            // Rollback: keep dialog open, show "Rolling back...", wait for event
            log.info('Rolling back operation: {operationId}', { operationId })
            isRollingBack = true
            isCancelling = true
            try {
                await cancelWriteOperation(operationId, true)
                log.debug('Rollback request sent successfully')
                // Dialog will close when write-cancelled event is received
            } catch (err) {
                log.error('Failed to rollback operation: {error}', { error: err })
                isRollingBack = false
                isCancelling = false
            }
        } else {
            // Cancel: close immediately, keep partial files
            log.info('Cancelling operation (keeping partial files): {operationId}', { operationId })
            isCancelling = true
            try {
                await cancelWriteOperation(operationId, false)
                log.debug('Cancel request sent successfully')
                // Close immediately without waiting for backend confirmation
                cleanup()
                onCancelled(filesDone)
            } catch (err) {
                log.error('Failed to cancel operation: {error}', { error: err })
                isCancelling = false
            }
        }
    }

    function handleKeydown(event: KeyboardEvent) {
        if (event.key === 'Tab') {
            // Trap focus within the dialog
            const overlay = event.currentTarget as HTMLElement
            const focusableElements = overlay.querySelectorAll<HTMLElement>(
                'button:not([disabled]), input:not([disabled]), [tabindex]:not([tabindex="-1"])',
            )
            if (focusableElements.length === 0) return

            const firstElement = focusableElements[0]
            const lastElement = focusableElements[focusableElements.length - 1]

            if (event.shiftKey) {
                if (document.activeElement === firstElement) {
                    event.preventDefault()
                    lastElement.focus()
                }
            } else {
                if (document.activeElement === lastElement) {
                    event.preventDefault()
                    firstElement.focus()
                }
            }
        }
    }

    onMount(() => {
        void startOperation()
    })

    onDestroy(() => {
        destroyed = true
        if (operationId) {
            // Cancel with rollback on unexpected teardown (hot-reload, navigation, crash).
            // Normal user-initiated cancel/complete already ran cleanup() + callbacks,
            // and the backend ignores cancel on finished operations (idempotent).
            void cancelWriteOperation(operationId, true)
        }
        cleanup()
    })
</script>

<ModalDialog
    titleId="progress-dialog-title"
    onkeydown={handleKeydown}
    dialogId="transfer-progress"
    onclose={() => void handleCancel(false)}
    containerStyle="min-width: 420px; max-width: 500px"
>
    {#snippet title()}
        {#if isRollingBack}
            Rolling back...
        {:else if conflictEvent}
            File already exists
        {:else if isMtpMove && mtpMovePhase === 'delete'}
            Removing source files...
        {:else}
            {operationGerund}...
        {/if}
    {/snippet}

    {#if !isDeleteOrTrash && conflictEvent}
        <!-- Conflict resolution (copy/move only) -->
        {@const fileName = conflictEvent.destinationPath.split('/').pop() ?? ''}
        {@const existingIsNewer = conflictEvent.destinationIsNewer}
        {@const newIsNewer = !existingIsNewer && conflictEvent.sourceModified !== conflictEvent.destinationModified}
        {@const existingIsLarger = conflictEvent.sizeDifference > 0}
        {@const newIsLarger = conflictEvent.sizeDifference < 0}
        <div class="conflict-section">
            <!-- Filename -->
            <p class="conflict-filename" use:tooltip={{ text: conflictEvent.destinationPath, overflowOnly: true }}>
                {fileName}
            </p>

            <!-- File comparison -->
            <div class="conflict-comparison">
                <div class="conflict-file">
                    <span class="conflict-file-label">Existing:</span>
                    <span class="conflict-file-size {getSizeColorClass(conflictEvent.destinationSize)}"
                        >{formatFileSize(conflictEvent.destinationSize)}</span
                    >
                    {#if existingIsLarger}<span class="conflict-annotation larger">(larger)</span>{/if}
                    <span class="conflict-file-date"
                        >{conflictEvent.destinationModified ? formatDate(conflictEvent.destinationModified) : ''}</span
                    >
                    {#if existingIsNewer}<span class="conflict-annotation newer">(newer)</span>{/if}
                </div>
                <div class="conflict-file">
                    <span class="conflict-file-label">New:</span>
                    <span class="conflict-file-size {getSizeColorClass(conflictEvent.sourceSize)}"
                        >{formatFileSize(conflictEvent.sourceSize)}</span
                    >
                    {#if newIsLarger}<span class="conflict-annotation larger">(larger)</span>{/if}
                    <span class="conflict-file-date"
                        >{conflictEvent.sourceModified ? formatDate(conflictEvent.sourceModified) : ''}</span
                    >
                    {#if newIsNewer}<span class="conflict-annotation newer">(newer)</span>{/if}
                </div>
            </div>

            <!-- Question -->
            <p class="conflict-question">Do you want to keep the existing file or overwrite it?</p>

            <!-- Buttons in two rows -->
            <div class="conflict-buttons">
                <div class="conflict-buttons-row">
                    <Button
                        variant="secondary"
                        onclick={() => handleConflictResolution('skip', false)}
                        disabled={isResolvingConflict}
                    >
                        Skip
                    </Button>
                    <Button
                        variant="secondary"
                        onclick={() => handleConflictResolution('overwrite', false)}
                        disabled={isResolvingConflict}
                    >
                        Overwrite
                    </Button>
                </div>
                <div class="conflict-buttons-row">
                    <Button
                        variant="secondary"
                        onclick={() => handleConflictResolution('skip', true)}
                        disabled={isResolvingConflict}
                    >
                        Skip all
                    </Button>
                    <Button
                        variant="secondary"
                        onclick={() => handleConflictResolution('overwrite', true)}
                        disabled={isResolvingConflict}
                    >
                        Overwrite all
                    </Button>
                </div>
            </div>

            <!-- Cancel at bottom -->
            <div class="conflict-cancel">
                {#if isCopy}
                    <button
                        class="danger-text"
                        onclick={() => handleCancel(true)}
                        disabled={isCancelling || isResolvingConflict}
                    >
                        Rollback
                    </button>
                {:else}
                    <button
                        class="danger-text"
                        onclick={() => handleCancel(false)}
                        disabled={isCancelling || isResolvingConflict}
                    >
                        Cancel
                    </button>
                {/if}
            </div>
        </div>
    {:else if isCopy && isRollingBack}
        <!-- Rollback in progress (copy only) -->
        <div class="rollback-section">
            <div class="rollback-indicator">
                <span class="spinner spinner-md rollback-spinner"></span>
            </div>
            <p class="rollback-message">
                Deleting {filesDone} copied files...
            </p>
        </div>
    {:else}
        <!-- Direction indicator (copy/move only) -->
        {#if !isDeleteOrTrash && destinationPath && direction}
            <DirectionIndicator sourcePath={sourceFolderPath} {destinationPath} {direction} />
        {/if}

        <!-- Progress stages -->
        <div class="progress-stages">
            {#each stages as stage (stage.id)}
                {@const status = getStageStatus(stage.id)}
                <div class="stage" class:done={status === 'done'} class:active={status === 'active'}>
                    <div class="stage-indicator">
                        {#if status === 'done'}
                            <span class="checkmark">&#10003;</span>
                        {:else if status === 'active'}
                            <span class="spinner spinner-sm stage-spinner"></span>
                        {:else}
                            <span class="dot"></span>
                        {/if}
                    </div>
                    <span>{stage.label}</span>
                </div>
                {#if stage.id !== stages[stages.length - 1].id}
                    <div class="stage-connector" class:done={status === 'done'}></div>
                {/if}
            {/each}
        </div>

        <!-- Progress bar -->
        <div class="progress-section">
            <div class="progress-bar-container">
                <div class="progress-bar" style="width: {percentComplete}%"></div>
            </div>
            <div class="progress-info">
                <span class="progress-percent">{Math.round(percentComplete)}%</span>
                {#if stats.estimatedSecondsRemaining !== null}
                    <span class="eta">~{formatDuration(stats.estimatedSecondsRemaining)} remaining</span>
                {/if}
            </div>
        </div>

        <!-- Stats -->
        <div class="stats-section">
            <div class="stat-row">
                <span class="stat-label">{operationType === 'trash' ? 'Items:' : 'Files:'}</span>
                <span class="stat-value">{filesDone} / {filesTotal}</span>
            </div>
            <div class="stat-row">
                <span class="stat-label">Size:</span>
                <span class="stat-value">{formatBytes(bytesDone)} / {formatBytes(bytesTotal)}</span>
            </div>
            {#if stats.bytesPerSecond > 0}
                <div class="stat-row">
                    <span class="stat-label">Speed:</span>
                    <span class="stat-value">{formatBytes(stats.bytesPerSecond)}/s</span>
                </div>
            {/if}
        </div>

        <!-- Current file -->
        {#if currentFile}
            <div class="current-file" use:tooltip={{ text: currentFile, overflowOnly: true }}>
                {currentFile}
            </div>
        {/if}

        <!-- Action buttons -->
        <div class="button-row">
            <Button variant="secondary" onclick={() => handleCancel(false)} disabled={isCancelling}>Cancel</Button>
            {#if isCopy}
                <span use:tooltip={'Cancel and delete any partial target files created'}>
                    <Button variant="danger" onclick={() => handleCancel(true)} disabled={isCancelling}>Rollback</Button
                    >
                </span>
            {/if}
        </div>
    {/if}
</ModalDialog>

