  1→<script lang="ts">
  2→    import { onMount, onDestroy } from 'svelte'
  3→    import {
  4→        formatBytes,
  5→        startScanPreview,
  6→        cancelScanPreview,
  7→        onScanPreviewProgress,
  8→        onScanPreviewComplete,
  9→        onScanPreviewError,
 10→        onScanPreviewCancelled,
 11→        type UnlistenFn,
 12→    } from '$lib/tauri-commands'
 13→    import type { SortColumn, SortOrder } from '$lib/file-explorer/types'
 14→    import { getSetting } from '$lib/settings'
 15→    import ModalDialog from '$lib/ui/ModalDialog.svelte'
 16→    import Button from '$lib/ui/Button.svelte'
 17→    import {
 18→        generateDeleteTitle,
 19→        abbreviatePath,
 20→        getSymlinkNotice,
 21→        MAX_VISIBLE_ITEMS,
 22→        type DeleteSourceItem,
 23→    } from './delete-dialog-utils'
 24→    import { formatFileSize } from '$lib/settings/reactive-settings.svelte'
 25→    import { getAppLogger } from '$lib/logging/logger'
 26→
 27→    const log = getAppLogger('deleteDialog')
 28→
 29→    interface Props {
 30→        sourceItems: DeleteSourceItem[]
 31→        sourcePaths: string[]
 32→        sourceFolderPath: string
 33→        isPermanent: boolean
 34→        supportsTrash: boolean
 35→        isFromCursor: boolean
 36→        /** Current sort column on source pane (for scan preview ordering) */
 37→        sortColumn: SortColumn
 38→        /** Current sort order on source pane */
 39→        sortOrder: SortOrder
 40→        onConfirm: (previewId: string | null) => void
 41→        onCancel: () => void
 42→    }
 43→
 44→    const {
 45→        sourceItems,
 46→        sourcePaths,
 47→        sourceFolderPath,
 48→        isPermanent: initialIsPermanent,
 49→        supportsTrash,
 50→        isFromCursor,
 51→        sortColumn,
 52→        sortOrder,
 53→        onConfirm,
 54→        onCancel,
 55→    }: Props = $props()
 56→
 57→    // Force permanent when trash not supported
 58→    const isPermanent = $derived(initialIsPermanent || !supportsTrash)
 59→
 60→    const dialogTitle = $derived(generateDeleteTitle(sourceItems, isFromCursor))
 61→    const abbreviatedPath = $derived(abbreviatePath(sourceFolderPath))
 62→    const symlinkNotice = $derived(getSymlinkNotice(sourceItems))
 63→
 64→    const visibleItems = $derived(sourceItems.slice(0, MAX_VISIBLE_ITEMS))
 65→    const overflowCount = $derived(Math.max(0, sourceItems.length - MAX_VISIBLE_ITEMS))
 66→
 67→    const confirmLabel = $derived(isPermanent ? 'Delete permanently' : 'Move to trash')
 68→    const confirmVariant = $derived<'primary' | 'danger'>(isPermanent ? 'danger' : 'primary')
 69→    const dialogRole = $derived<'dialog' | 'alertdialog'>(isPermanent ? 'alertdialog' : 'dialog')
 70→
 71→    // Scan preview state
 72→    let previewId = $state<string | null>(null)
 73→    let filesFound = $state(0)
 74→    let dirsFound = $state(0)
 75→    let bytesFound = $state(0)
 76→    let isScanning = $state(false)
 77→    let scanComplete = $state(false)
 78→    let unlisteners: UnlistenFn[] = []
 79→
 80→    /** Accepts the event if it belongs to our scan, filtering stale events from previous scans. */
 81→    function isOurScanEvent(eventPreviewId: string): boolean {
 82→        if (!previewId) previewId = eventPreviewId
 83→        return eventPreviewId === previewId
 84→    }
 85→
 86→    /** Starts the scan preview to count files/dirs/bytes. */
 87→    async function startScan() {
 88→        // Subscribe to events BEFORE starting scan (avoid missing fast completions)
 89→        unlisteners.push(
 90→            await onScanPreviewProgress((event) => {
 91→                if (!isOurScanEvent(event.previewId)) return
 92→                filesFound = event.filesFound
 93→                dirsFound = event.dirsFound
 94→                bytesFound = event.bytesFound
 95→            }),
 96→        )
 97→        unlisteners.push(
 98→            await onScanPreviewComplete((event) => {
 99→                if (!isOurScanEvent(event.previewId)) return
100→                filesFound = event.filesTotal
101→                dirsFound = event.dirsTotal
102→                bytesFound = event.bytesTotal
103→                isScanning = false
104→                scanComplete = true
105→            }),
106→        )
107→        unlisteners.push(
108→            await onScanPreviewError((event) => {
109→                if (!isOurScanEvent(event.previewId)) return
110→                isScanning = false
111→                // Keep showing whatever stats we have
112→            }),
113→        )
114→        unlisteners.push(
115→            await onScanPreviewCancelled((event) => {
116→                if (!isOurScanEvent(event.previewId)) return
117→                isScanning = false
118→            }),
119→        )
120→
121→        // Start the scan
122→        isScanning = true
123→        const progressIntervalMs = getSetting('fileOperations.progressUpdateInterval')
124→        const result = await startScanPreview(sourcePaths, sortColumn, sortOrder, progressIntervalMs)
125→        previewId = result.previewId
126→    }
127→
128→    function cleanup() {
129→        for (const unlisten of unlisteners) {
130→            unlisten()
131→        }
132→        unlisteners = []
133→    }
134→
135→    onMount(() => {
136→        void startScan()
137→    })
138→
139→    onDestroy(() => {
140→        if (previewId && isScanning) {
141→            void cancelScanPreview(previewId)
142→        }
143→        cleanup()
144→    })
145→
146→    function handleConfirm() {
147→        log.info('Delete confirmed: isPermanent={isPermanent}, items={count}', {
148→            isPermanent,
149→            count: sourceItems.length,
150→        })
151→        onConfirm(previewId)
152→    }
153→
154→    function handleCancel() {
155→        if (previewId && isScanning) {
156→            void cancelScanPreview(previewId)
157→        }
158→        cleanup()
159→        onCancel()
160→    }
161→
162→    function handleKeydown(event: KeyboardEvent) {
163→        if (event.key === 'Enter') {
164→            handleConfirm()
165→        }
166→    }
167→
168→    /** Formats item size for display. Folders show recursive info when available.
169→     *  Always uses logical (content) sizes — not worth plumbing the display mode setting
170→     *  through the delete dialog infrastructure for a transient confirmation dialog. */
171→    function formatItemSize(item: DeleteSourceItem): string {
172→        if (item.isDirectory) {
173→            const size = item.recursiveSize
174→            const fileCount = item.recursiveFileCount
175→            const parts: string[] = []
176→            if (size !== undefined) parts.push(formatFileSize(size))
177→            if (fileCount !== undefined) {
178→                parts.push(`${String(fileCount)} ${fileCount === 1 ? 'file' : 'files'}`)
179→            }
180→            return parts.length > 0 ? parts.join('   ') : ''
181→        }
182→        return item.size !== undefined ? formatFileSize(item.size) : ''
183→    }
184→</script>
