601→    function handleKeydown(event: KeyboardEvent) {
602→        if (event.key === 'Tab') {
603→            // Trap focus within the dialog
604→            const overlay = event.currentTarget as HTMLElement
605→            const focusableElements = overlay.querySelectorAll<HTMLElement>(
606→                'button:not([disabled]), input:not([disabled]), [tabindex]:not([tabindex="-1"])',
607→            )
608→            if (focusableElements.length === 0) return
609→
610→            const firstElement = focusableElements[0]
611→            const lastElement = focusableElements[focusableElements.length - 1]
612→
613→            if (event.shiftKey) {
614→                if (document.activeElement === firstElement) {
615→                    event.preventDefault()
616→                    lastElement.focus()
617→                }
618→            } else {
619→                if (document.activeElement === lastElement) {
620→                    event.preventDefault()
621→                    firstElement.focus()
622→                }
623→            }
624→        }
625→    }
