 20→    /* === Borders === */
 21→    --color-border-strong: #bbb;
 22→    --color-border: #ddd;
 23→    --color-border-subtle: #e8e8e8;
 24→
 25→    /* === Text === */
 26→    --color-text-primary: #1a1a1a;
 27→    --color-text-secondary: #666666;
 28→    --color-text-tertiary: #888888;
 29→
 30→    /* === macOS system accent colors (for reference / testing) ===
 31→     * These are the fixed colors returned by NSColor.controlAccentColor().
 32→     * "Multicolor" (the default macOS option) returns Blue. */
 33→    --color-apple-blue: #087aff;
 34→    --color-apple-purple: #a54fa7;
 35→    --color-apple-pink: #f74f9f;
 36→    --color-apple-red: #ff5157;
 37→    --color-apple-orange: #f6821b;
 38→    --color-apple-yellow: #ffc601;
 39→    --color-apple-green: #61bb46;
 40→    --color-apple-graphite: #8b8c8c;
 41→
 42→    /* === Interactive States ===
 43→     * These accent colors are CSS fallbacks only. At runtime, the Rust backend
 44→     * reads the macOS system accent color and overrides --color-accent via
 45→     * accent-color.ts → initAccentColor(). See src-tauri/src/accent_color.rs. */
 46→    --color-accent: #d4a006;
 47→    --color-accent-fg: #1a1a1a; /* Text on accent backgrounds — dark in both themes for a11y */
 48→    --color-accent-hover: color-mix(in oklch, var(--color-accent), white 15%);
 49→    --color-accent-subtle: color-mix(in oklch, var(--color-accent), transparent 85%);
 50→    --color-cmdr-gold: #d4a006;
 51→    --color-cmdr-blue: #4a9eff;
 52→    --color-cmdr-purple: #7c3aed;
 53→    --color-system-accent: #d4a006; /* Updated at runtime by accent-color.ts */
 54→
 55→    /* === Cursor (row highlight in file lists) === */
 56→    --color-cursor-inactive: color-mix(in srgb, var(--color-bg-tertiary), transparent 60%);
 57→    --color-cursor-active: color-mix(in oklch, var(--color-accent), transparent 80%);
