151→/// Gets the detailed status of a specific operation.
152→///
153→/// Returns `None` if the operation is not found (either never existed or already completed).
154→pub fn get_operation_status(operation_id: &str) -> Option<OperationStatus> {
155→    let cache = OPERATION_STATUS_CACHE.read().ok()?;
156→    let status = cache.get(operation_id)?;
157→
158→    // Check if the operation is still running
159→    let is_running = WRITE_OPERATION_STATE
160→        .read()
161→        .ok()
162→        .map(|c| c.contains_key(operation_id))
163→        .unwrap_or(false);
164→
165→    Some(OperationStatus {
166→        operation_id: operation_id.to_string(),
167→        operation_type: status.operation_type,
168→        phase: status.phase,
169→        is_running,
170→        current_file: status.current_file.clone(),
171→        files_done: status.files_done,
172→        files_total: status.files_total,
173→        bytes_done: status.bytes_done,
174→        bytes_total: status.bytes_total,
175→        started_at: status.started_at,
176→    })
177→}
