19→// ============================================================================
20→// Core trash function (reusable by commands/rename.rs and batch trash)
21→// ============================================================================
22→
23→/// Synchronous trash implementation using macOS NSFileManager.trashItem.
24→///
25→/// Uses `symlink_metadata()` for existence checks so dangling symlinks
26→/// are handled correctly (the link itself exists even if its target doesn't).
27→#[cfg(target_os = "macos")]
28→pub fn move_to_trash_sync(path: &Path) -> Result<(), String> {
29→    use objc2::rc::autoreleasepool;
30→    use objc2_foundation::{NSFileManager, NSString, NSURL};
31→
32→    if fs::symlink_metadata(path).is_err() {
33→        return Err(format!("'{}' doesn't exist", path.display()));
34→    }
35→
36→    // Drain autoreleased ObjC objects (NSURL, NSString, NSFileManager internals).
37→    // Called from spawn_blocking threads that lack AppKit's autorelease pool.
38→    autoreleasepool(|_| {
39→        let path_str = path.to_string_lossy();
40→        let ns_path = NSString::from_str(&path_str);
41→        let url = NSURL::fileURLWithPath(&ns_path);
42→        let file_manager = NSFileManager::defaultManager();
43→
44→        // trashItemAtURL:resultingItemURL:error: moves the item to Trash.
45→        // We pass None for resultingItemURL since we don't need the trash location.
46→        file_manager
47→            .trashItemAtURL_resultingItemURL_error(&url, None)
48→            .map_err(|e| format!("Failed to move to trash: {}", e))?;
49→        Ok(())
50→    })
51→}
52→
53→#[cfg(target_os = "linux")]
54→pub fn move_to_trash_sync(path: &Path) -> Result<(), String> {
55→    if fs::symlink_metadata(path).is_err() {
56→        return Err(format!("'{}' doesn't exist", path.display()));
57→    }
58→
59→    trash::delete(path).map_err(|e| format!("Failed to move to trash: {}", e))
60→}
61→
62→#[cfg(not(any(target_os = "macos", target_os = "linux")))]
63→pub fn move_to_trash_sync(path: &Path) -> Result<(), String> {
64→    Err(format!(
65→        "Moving to trash is not supported on this platform for '{}'",
66→        path.display()
67→    ))
68→}
