22→pub(super) fn delete_files_with_progress(
23→    app: &tauri::AppHandle,
24→    operation_id: &str,
25→    state: &Arc<WriteOperationState>,
26→    sources: &[PathBuf],
27→    config: &WriteOperationConfig,
28→) -> Result<(), WriteOperationError> {
29→    use tauri::Emitter;
30→
31→    // Phase 1: Scan to get file count (delete uses default sorting)
32→    let scan_result = scan_sources(
33→        sources,
34→        state,
35→        app,
36→        operation_id,
37→        WriteOperationType::Delete,
38→        config.sort_column,
39→        config.sort_order,
40→    )?;
41→
42→    // Handle dry-run mode (delete has no conflicts)
43→    if config.dry_run {
44→        let result = DryRunResult {
45→            operation_id: operation_id.to_string(),
46→            operation_type: WriteOperationType::Delete,
47→            files_total: scan_result.file_count,
48→            bytes_total: scan_result.total_bytes,
49→            conflicts_total: 0,
50→            conflicts: Vec::new(),
51→            conflicts_sampled: false,
52→        };
53→
54→        let _ = app.emit("dry-run-complete", result);
55→        return Ok(());
56→    }
57→
58→    // Phase 2: Delete files first (deepest first)
59→    let mut files_done = 0;
60→    let mut bytes_done = 0u64;
61→    let mut last_progress_time = Instant::now();
62→
63→    let mut tracker = SourceItemTracker::new(&scan_result.files);
64→
65→    // Delete files
66→    for file_info in &scan_result.files {
67→        // Check cancellation
68→        if state.cancelled.load(Ordering::Relaxed) {
69→            let _ = app.emit(
70→                "write-cancelled",
71→                WriteCancelledEvent {
72→                    operation_id: operation_id.to_string(),
73→                    operation_type: WriteOperationType::Delete,
74→                    files_processed: files_done,
75→                    rolled_back: false, // Delete operations can't be rolled back
76→                },
77→            );
78→            return Err(WriteOperationError::Cancelled {
79→                message: "Operation cancelled by user".to_string(),
80→            });

