 81→/// Moves files to trash with progress reporting, cancellation, and partial failure.
 82→///
 83→/// Iterates top-level items, calling `move_to_trash_sync()` for each.
 84→/// Unlike permanent delete, trash doesn't need a recursive scan phase because
 85→/// `trashItemAtURL` is atomic per top-level item (the OS moves the entire tree).
 86→///
 87→/// # Arguments
 88→/// * `app` - Tauri app handle for event emission
 89→/// * `operation_id` - Unique operation ID for event correlation
 90→/// * `state` - Shared state with cancellation flag and progress interval
 91→/// * `sources` - Top-level items to trash
 92→/// * `item_sizes` - Optional per-item sizes for byte-level progress (from scan
 93→///   preview or drive index). When `None`, bytes progress is not reported.
 94→pub(super) fn trash_files_with_progress(
 95→    app: &tauri::AppHandle,
 96→    operation_id: &str,
 97→    state: &Arc<WriteOperationState>,
 98→    sources: &[PathBuf],
 99→    item_sizes: Option<&[u64]>,
100→) -> Result<(), WriteOperationError> {
101→    use tauri::Emitter;
102→
103→    let items_total = sources.len();
104→    let bytes_total: u64 = item_sizes.map(|s| s.iter().sum()).unwrap_or(0);
105→
106→    let mut items_done = 0usize;
107→    let mut bytes_done = 0u64;
108→    let mut errors: Vec<TrashItemError> = Vec::new();
109→    let mut last_progress_time = Instant::now();
110→
111→    for (i, source) in sources.iter().enumerate() {
112→        // Check cancellation between items
113→        if state.cancelled.load(Ordering::Relaxed) {
114→            let _ = app.emit(
115→                "write-cancelled",
116→                WriteCancelledEvent {
117→                    operation_id: operation_id.to_string(),
118→                    operation_type: WriteOperationType::Trash,
119→                    files_processed: items_done,
120→                    rolled_back: false, // Trash is recoverable, no rollback needed
121→                },
122→            );
123→            return Err(WriteOperationError::Cancelled {
124→                message: "Operation cancelled by user".to_string(),
125→            });
126→        }
127→
128→        // Check existence using symlink_metadata (handles dangling symlinks)
129→        if fs::symlink_metadata(source).is_err() {
130→            errors.push(TrashItemError {
131→                path: source.clone(),
132→                message: format!("'{}' no longer exists", source.display()),
133→            });
134→            continue;
135→        }
136→
137→        // Attempt to trash the item
138→        match move_to_trash_sync(source) {
139→            Ok(()) => {
140→                items_done += 1;
141→                if let Some(sizes) = item_sizes
142→                    && let Some(&size) = sizes.get(i)
143→                {
144→                    bytes_done += size;
145→                }
146→
147→                let _ = app.emit(
148→                    "write-source-item-done",
149→                    WriteSourceItemDoneEvent {
150→                        operation_id: operation_id.to_string(),
151→                        source_path: source.display().to_string(),
152→                    },
153→                );
154→            }
155→            Err(e) => {
156→                errors.push(TrashItemError {
157→                    path: source.clone(),
158→                    message: e,
159→                });
160→                continue;
161→            }
162→        }
163→
164→        // Emit throttled progress
165→        if last_progress_time.elapsed() >= state.progress_interval {
166→            let current_file = source.file_name().map(|n| n.to_string_lossy().to_string());
167→            let _ = app.emit(
168→                "write-progress",
169→                WriteProgressEvent {
170→                    operation_id: operation_id.to_string(),
171→                    operation_type: WriteOperationType::Trash,
172→                    phase: WriteOperationPhase::Trashing,
173→                    current_file: current_file.clone(),
174→                    files_done: items_done,
175→                    files_total: items_total,
176→                    bytes_done,
177→                    bytes_total,
178→                },
179→            );
180→            update_operation_status(
181→                operation_id,
182→                WriteOperationPhase::Trashing,
183→                current_file,
184→                items_done,
185→                items_total,
186→                bytes_done,
187→                bytes_total,
188→            );
189→            last_progress_time = Instant::now();
190→        }
191→    }
192→
193→    // Spawn async sync for durability (non-blocking)
194→    spawn_async_sync();
195→
196→    // If all items failed, emit error
197→    if items_done == 0 && !errors.is_empty() {
