634→            // Cancel with rollback on unexpected teardown (hot-reload, navigation, crash).
635→            // Normal user-initiated cancel/complete already ran cleanup() + callbacks,
636→            // and the backend ignores cancel on finished operations (idempotent).
637→            void cancelWriteOperation(operationId, true)
638→        }
639→        cleanup()
640→    })
